-- 1. Plumbers × Web Design
INSERT INTO public.industry_content (industry_slug, service_slug, intro_paragraph, why_needed, approach_difference, pain_points, solutions, faqs)
VALUES (
  'plumbers',
  'web-design',
  'When a pipe bursts at midnight or a boiler fails in January, the homeowner''s first action is a frantic Google search followed by a snap judgement about whichever plumber''s website they land on. Your website has roughly five seconds to communicate three things: you are qualified, you are available, and you can be contacted instantly. Most plumbing websites fail this test — phone numbers are buried in contact pages, Gas Safe registration numbers are hidden in footer text, and there is no indication of whether you handle emergencies, boiler installations, or bathroom fitting. A plumbing website must serve two distinct audiences simultaneously: the panicked homeowner with water pouring through their ceiling who needs a number to call right now, and the considered buyer researching a new boiler or bathroom renovation who needs to see credentials, completed projects, and transparent pricing guides. We build plumbing websites that convert both emergency callers and planned-project researchers with a design that puts trust signals and contact methods exactly where each audience needs them.',
  'Plumbing is a trust-critical trade — customers are inviting you into their homes to work on systems that, if done incorrectly, risk water damage, gas leaks, or both. Your website must immediately establish credibility through visible Gas Safe registration, insurance details, and manufacturer accreditations. Without these trust signals presented prominently, homeowners choose the competitor whose site makes them feel safest. Emergency callers who cannot find your number in two seconds call someone else.',
  'We design around the split nature of plumbing work: emergency callouts needing instant mobile contact, and planned projects needing detailed service pages. A persistent click-to-call emergency banner sits above the fold on every mobile page. Planned service sections cover boiler installations, bathroom fitting, and central heating with manufacturer logos, completed project galleries, and transparent pricing guidance.',
  '[{"title": "Emergency callers cannot find your phone number fast enough", "description": "When water is flooding a kitchen or a boiler has stopped working in freezing temperatures, homeowners will not navigate menus or scroll through service descriptions. If your phone number is not visible and tappable within two seconds on mobile, they hit the back button and call the next plumber Google shows them."}, {"title": "Gas Safe and manufacturer accreditations not prominently displayed", "description": "Gas Safe registration is a legal requirement for gas work and the most important trust signal for boiler installations. Most plumbing websites either bury the registration number in small footer text or display no accreditation at all, losing customers to competitors who make their qualifications impossible to miss."}, {"title": "No separation between emergency services and planned projects", "description": "A homeowner researching a bathroom renovation has completely different needs from someone with a burst pipe. When both audiences land on the same generic services page, neither finds what they need quickly enough. Emergency callers cannot find the phone number, and renovation researchers cannot find the portfolio or pricing information they need."}]',
  '[{"title": "Emergency-first mobile design with persistent click-to-call", "description": "A high-contrast emergency banner with your phone number visible on every page without scrolling. On mobile, a single tap initiates the call. After-hours messaging confirms emergency availability. This captures the urgent callout work that generates the highest per-hour revenue in plumbing."}, {"title": "Trust-forward Gas Safe and manufacturer accreditation display", "description": "Your Gas Safe registration number with a direct verification link, manufacturer accreditation logos for brands like Worcester Bosch, Vaillant, and Baxi, and public liability insurance details are displayed prominently across the site. This independent verification converts cautious homeowners who are comparing plumbers on trust."}, {"title": "Dual-pathway design for emergencies and planned work", "description": "Clear visual separation between emergency services and planned projects. Emergency visitors see immediate contact options and service coverage. Planned-project visitors find detailed boiler installation guides, bathroom fitting portfolios, and central heating service pages with pricing guidance and booking forms."}]',
  '[{"question": "How do you make a plumbing website generate emergency callout work?", "answer": "Emergency design prioritises speed and visibility. We place a clickable phone number in a high-contrast banner visible without scrolling on every mobile page. Schema markup tells Google your business handles emergency plumbing, and after-hours messaging confirms you take urgent calls. This captures the highest-value work in plumbing."}, {"question": "Can customers verify my Gas Safe registration through the website?", "answer": "Yes. We display your Gas Safe registration number with a direct link to the Gas Safe Register verification page. Visitors can confirm your registration status independently, which builds far more trust than simply stating you are registered. Manufacturer accreditation logos are displayed alongside with links to their approved installer directories."}, {"question": "Should I show pricing on my plumbing website?", "answer": "We recommend indicative pricing ranges or starting-from prices for common services like boiler installations, power flush treatments, and bathroom fitting. This sets expectations, reduces tyre-kicker enquiries, and attracts customers who are serious about proceeding at your price point. Exact quotes still require a site visit."}, {"question": "Will the website work well on mobile phones?", "answer": "Over seventy percent of plumbing enquiries come from mobile devices, and for emergencies that figure is even higher. Every site we build is mobile-first with fast loading times, tap-to-call functionality, and forms designed for thumb-friendly completion. Emergency features are specifically designed for panicked, one-handed phone use."}]'
)
ON CONFLICT (industry_slug, service_slug) DO UPDATE SET
  intro_paragraph = EXCLUDED.intro_paragraph,
  why_needed = EXCLUDED.why_needed,
  approach_difference = EXCLUDED.approach_difference,
  pain_points = EXCLUDED.pain_points,
  solutions = EXCLUDED.solutions,
  faqs = EXCLUDED.faqs;

-- 2. Plumbers × SEO
INSERT INTO public.industry_content (industry_slug, service_slug, intro_paragraph, why_needed, approach_difference, pain_points, solutions, faqs)
VALUES (
  'plumbers',
  'seo',
  'Plumbing generates some of the most commercially valuable local search traffic of any trade. Emergency searches like "emergency plumber near me" and "burst pipe plumber" represent customers willing to pay premium callout rates immediately. Planned searches like "boiler installation cost" and "bathroom fitter Kent" represent projects worth thousands of pounds. Yet the majority of plumbers have no SEO strategy whatsoever, relying on word of mouth, Checkatrade profiles, and paid Google Ads that disappear the moment the budget runs out. The plumbing trade has a natural SEO advantage: the breadth of services creates dozens of targetable keyword clusters. Boiler installations, central heating repairs, bathroom fitting, drain unblocking, leak detection, power flushing, and emergency callouts each represent separate search categories with distinct intent and competition levels. We build plumbing SEO campaigns that systematically capture traffic across every service you offer, prioritising the high-value emergency and boiler installation searches that deliver the greatest return on your investment.',
  'Emergency plumbing searches have among the highest conversion rates of any local service query. A homeowner with water pouring through their ceiling will call the first credible plumber they find. If your business is invisible for these searches, you are surrendering premium-rate callout work to whoever ranks above you. Beyond emergencies, boiler installation searches represent the single highest-value keyword cluster in domestic plumbing, often worth several thousand pounds per converted enquiry.',
  'We prioritise the searches that generate the most revenue per click: emergency plumbing terms with 24/7 schema markup, boiler installation keywords targeting specific manufacturers and fuel types, and bathroom fitting searches in your service area. Each service gets a dedicated landing page. Google Business Profile optimisation features completed project photos and a systematic review programme.',
  '[{"title": "Invisible for emergency plumbing searches in your area", "description": "Emergency plumbing searches spike at evenings, weekends, and during cold snaps when pipes freeze and boilers fail. The plumbers appearing in the Map Pack and top organic results for these searches capture work at premium callout rates. Without emergency-focused SEO, your business is invisible at the exact moments when customers will pay the most for immediate help."}, {"title": "Boiler installation searches dominated by national companies and directories", "description": "Searches like boiler installation cost and new boiler quotes are targeted aggressively by national heating companies like British Gas, and by Checkatrade and MyBuilder. Without dedicated, locally-optimised boiler content, your business is buried beneath these well-funded competitors for the highest-value planned work in plumbing."}, {"title": "No content targeting specific plumbing services beyond generic terms", "description": "A single services page listing everything from dripping taps to full central heating installations cannot rank for any specific search term. Customers searching for power flush, underfloor heating installation, or unvented cylinder fitting find competitors who have dedicated pages addressing those exact requirements."}]',
  '[{"title": "Emergency plumbing SEO with 24/7 schema markup", "description": "Dedicated emergency pages targeting burst pipe plumber, no hot water emergency, and leak repair urgent searches. LocalBusiness schema markup declares 24/7 availability, emergency service capability, and average response times. Google Business Profile optimisation ensures Map Pack visibility for after-hours urgent searches across your coverage area."}, {"title": "Boiler installation content targeting manufacturer and fuel-type searches", "description": "Comprehensive landing pages for boiler installations segmented by manufacturer — Worcester Bosch, Vaillant, Baxi, Ideal — and by fuel type and property type. Cost guides, efficiency comparisons, and grant eligibility information target the informational searches that precede high-value boiler purchase decisions."}, {"title": "Service-specific landing pages for every plumbing discipline", "description": "Individual optimised pages for bathroom fitting, central heating installation, power flushing, drain unblocking, leak detection, underfloor heating, unvented cylinders, and every other service you offer. Each page targets the specific terms homeowners search for that service, capturing traffic a generic page cannot."}]',
  '[{"question": "How quickly can I rank for emergency plumber searches?", "answer": "Google Business Profile optimisation can improve Map Pack visibility for emergency searches within four to six weeks. Organic rankings for emergency plumber plus your location typically require three to six months. We prioritise emergency visibility because it delivers the highest immediate revenue — a single captured emergency callout can cover months of SEO investment."}, {"question": "Is it worth targeting boiler installation keywords against British Gas?", "answer": "Yes. While you cannot outspend national companies on broad terms, local SEO targeting specific towns and postcodes is highly effective. Homeowners increasingly prefer local Gas Safe registered installers over national companies, and dedicated local content outranks generic national pages for location-specific searches."}, {"question": "How many Google reviews do I need to appear in the Map Pack?", "answer": "Consistency matters more than a specific number. We implement automated review request workflows triggered after each completed job. Most plumbers see meaningful Map Pack improvements after accumulating fifteen to twenty recent, detailed reviews. The recency and specificity of reviews matters as much as the total count."}, {"question": "Can SEO reduce my spend on Google Ads?", "answer": "Yes. As organic rankings and Map Pack visibility improve, direct enquiries increase and your reliance on paid advertising decreases. Most plumbing clients maintain a small Ads budget for emergency terms during the early months, then gradually reduce it as organic visibility strengthens. The long-term cost per lead from SEO is significantly lower than paid advertising."}]'
)
ON CONFLICT (industry_slug, service_slug) DO UPDATE SET
