  faqs = EXCLUDED.faqs;

-- 3. Plumbers × Lead Capture
INSERT INTO public.industry_content (industry_slug, service_slug, intro_paragraph, why_needed, approach_difference, pain_points, solutions, faqs)
VALUES (
  'plumbers',
  'lead-capture',
  'Plumbing websites typically only capture visitors who are ready to call or fill in a contact form right now — and that represents a small fraction of total traffic. The homeowner researching boiler replacements three months before their current system fails, the landlord comparing plumbers for a property portfolio, and the couple browsing bathroom fitting ideas are all high-value prospects who visit your site and leave without a trace. Effective lead capture for plumbers means offering tools that provide genuine value at every stage of the buying journey: a boiler replacement cost calculator for the researcher, a landlord property maintenance checklist for the portfolio owner, and a bathroom project planner for the couple designing their renovation. Each tool captures contact details and project specifications in exchange for information the visitor actually wants, transforming anonymous browsers into named prospects with defined requirements. We build lead capture systems for plumbing businesses that convert casual researchers into booked consultations and repeat maintenance customers.',
  'Plumbing projects range from emergency callouts requiring no lead capture to boiler installations and bathroom renovations involving weeks of research. For these considered purchases, customers visit multiple plumber websites before choosing. Without capturing their details during the research phase, you lose every prospect who does not call on their first visit. A structured lead capture system ensures you have their contact information and project requirements, allowing proactive follow-up through the decision period.',
  'We build plumbing-specific lead magnets: boiler replacement cost calculators asking about property size, current system type, and fuel preferences; bathroom project planners collecting room dimensions and design preferences; and landlord gas safety compliance checklists. Each tool captures details and feeds into an automated follow-up sequence.',
  '[{"title": "Boiler replacement researchers leaving without making contact", "description": "A homeowner researching new boilers visits an average of four to five plumber websites before requesting a quote. Without a compelling reason to share their details — like a personalised cost estimate — these high-value prospects remain anonymous. You cannot follow up, and they choose whichever plumber they remember or find again when ready."}, {"title": "Landlords comparing plumbers with no way to capture their details", "description": "Landlords managing multiple properties represent the most valuable long-term plumbing customers, generating recurring gas safety checks, boiler servicing, and emergency callout work. Without lead magnets addressing landlord-specific concerns — compliance deadlines, portfolio management, preferred contractor arrangements — these prospects slip away to competitors."}, {"title": "Generic contact forms collecting insufficient project information", "description": "A contact form asking for name, email, and message produces vague enquiries that require extensive back-and-forth before you can provide a meaningful quote. Without knowing the property type, current boiler model, number of radiators, or bathroom dimensions, every initial response is a generic request for more information."}]',
  '[{"title": "Boiler replacement cost calculator", "description": "An interactive tool asking about property type, number of bedrooms and bathrooms, current boiler type, preferred fuel source, and any hot water requirements. Homeowners receive an indicative cost range for their specific situation. You receive their full contact details alongside detailed property and heating specifications ready for a site survey booking."}, {"title": "Landlord gas safety and compliance toolkit", "description": "A downloadable compliance checklist covering gas safety certificate deadlines, boiler servicing schedules, and legal obligations captures email addresses from landlords. A follow-up sequence positions your business as their preferred gas engineer, offering annual service contracts and priority emergency callout arrangements for their portfolio."}, {"title": "Bathroom project planner with design preferences", "description": "An interactive planner collecting room dimensions, fixture preferences, accessibility requirements, and budget range captures comprehensive project details from homeowners planning renovations. They receive a project summary document. You receive a fully qualified lead with specifications detailed enough to prepare a meaningful estimate before the site visit."}]',
  '[{"question": "What is the best lead magnet for a plumbing business?", "answer": "A boiler replacement cost calculator consistently generates the highest volume of qualified leads for plumbers. Homeowners are naturally curious about replacement costs, and the calculator provides personalised estimates that feel valuable. For businesses focused on bathroom fitting, a project planner with design preference collection performs equally well."}, {"question": "How does the boiler cost calculator work without committing me to a price?", "answer": "The calculator provides indicative ranges based on property type, boiler specifications, and complexity factors. Clear disclaimers explain that final pricing requires a site survey to assess pipework, flue routing, and installation access. The purpose is to give homeowners useful guidance while capturing their property details for your follow-up."}, {"question": "Can lead capture help me win landlord maintenance contracts?", "answer": "Yes. Landlord compliance toolkits and gas safety checklists capture details from property owners who need ongoing plumbing support. The automated follow-up sequence positions your business for annual gas safety inspections, boiler servicing contracts, and preferred contractor arrangements that generate reliable recurring revenue."}, {"question": "How do captured leads get delivered to me?", "answer": "Every lead generates an instant notification via email, SMS, or both with full project details. We integrate with CRM systems, Google Sheets, or whatever tools you already use. Each lead includes the prospect''s contact information, property details, project specifications, and any preferences they indicated."}]'
)
ON CONFLICT (industry_slug, service_slug) DO UPDATE SET
  intro_paragraph = EXCLUDED.intro_paragraph,
  why_needed = EXCLUDED.why_needed,
  approach_difference = EXCLUDED.approach_difference,
