  faqs = EXCLUDED.faqs;

-- 4. Plumbers × Business Automation
INSERT INTO public.industry_content (industry_slug, service_slug, intro_paragraph, why_needed, approach_difference, pain_points, solutions, faqs)
VALUES (
  'plumbers',
  'business-automation',
  'Plumbers spend their days under sinks, in loft spaces, and behind boilers — not sitting at desks managing admin. Yet the administrative demands of a plumbing business are relentless: quote requests arrive while you are elbow-deep in a repair, sent quotes go unfollowed because you are already on the next job, boiler service reminders need sending to hundreds of customers, gas safety certificate renewals need tracking across landlord portfolios, and completed jobs generate no reviews because you never got around to asking. Business automation for plumbers creates workflows that handle these repetitive tasks without your involvement. A new enquiry receives an instant acknowledgement with your availability. A sent quote triggers follow-up messages at forty-eight hours and one week. A completed boiler installation triggers a review request and schedules the first annual service reminder. Landlord customers receive automatic gas safety certificate renewal reminders sixty days before expiry. These are practical, trade-focused automations that keep your business running professionally while you focus on the work that generates revenue.',
  'Plumbers lose significant revenue annually to forgotten quote follow-ups, missed service renewal reminders, and uncollected reviews. When every working hour is spent on-site, admin tasks get pushed to late evenings and inevitably fall through the cracks. Automation ensures every enquiry gets an instant response, every quote gets chased, every boiler installation triggers a service reminder chain, and every completed job generates a review request. It transforms a busy sole trader into a professionally managed operation.',
  'We automate the plumbing business cycle: instant enquiry acknowledgements, quote follow-up sequences, job booking confirmations, post-completion review requests, annual boiler service reminders, gas safety certificate renewal tracking for landlord clients, and seasonal heating system check campaigns before winter.',
  '[{"title": "Quotes sent but never followed up while on the next job", "description": "A plumber sends a boiler installation quote on Monday, starts an emergency repair on Tuesday, and by Friday the quote has gone cold because no follow-up was sent. The customer, who was genuinely interested, chose the competitor who sent a polite check-in message on Wednesday. This pattern repeats weekly, costing thousands in lost revenue."}, {"title": "Boiler service reminders not sent to existing customers", "description": "Annual boiler servicing is a reliable revenue stream, but most plumbers have no system for reminding customers when their service is due. Without automated reminders, customers either forget about servicing entirely or search Google and find a different engineer when they do remember — losing you recurring income."}, {"title": "Gas safety certificate renewals missed for landlord clients", "description": "Landlords rely on their gas engineer to remind them when certificates are due for renewal. Tracking expiry dates across multiple properties using memory or spreadsheets inevitably leads to missed renewals, putting landlords at legal risk and damaging the trust that underpins your most valuable ongoing customer relationships."}]',
  '[{"title": "Automated quote follow-up sequences", "description": "Every sent quote triggers a timed sequence: a friendly check-in after forty-eight hours, a reminder after one week with a link to your reviews, and a final availability message after two weeks. Each message references the specific job details. Quote conversion rates typically improve by thirty to forty percent with consistent follow-up."}, {"title": "Boiler service and annual maintenance reminders", "description": "Every boiler installation and service automatically schedules a reminder for the following year. Customers receive a personalised message when their service is due, with a direct booking link. A follow-up reminder goes out if they do not respond within two weeks. This systematically generates recurring revenue from your existing customer base."}, {"title": "Gas safety certificate tracking for landlord portfolios", "description": "Every landlord property''s gas safety certificate expiry date is tracked automatically. Reminders go to both you and the landlord sixty days before expiry, with a booking link for the renewal visit. This protects landlords from legal non-compliance, demonstrates professional management, and secures your position as their preferred gas engineer."}]',
  '[{"question": "What plumbing business tasks can be automated?", "answer": "The highest-impact automations are enquiry acknowledgements, quote follow-ups, job booking confirmations, post-completion review requests, annual boiler service reminders, gas safety certificate renewal tracking, and seasonal heating check campaigns. We also automate appointment reminders, payment follow-ups, and warranty registration for new boiler installations."}, {"question": "How do gas safety certificate reminders work for my landlord clients?", "answer": "We record the expiry date for every gas safety certificate you issue. The system automatically sends reminders to both you and the landlord sixty days and thirty days before expiry. If no booking is made, escalation reminders follow. This ensures no certificate lapses, protecting your landlords from prosecution and securing your annual renewal visits."}, {"question": "Will automated quote follow-ups feel pushy to customers?", "answer": "No. Messages are personalised with the customer''s name and specific job details, timed at natural intervals, and written in a helpful rather than pressuring tone. Most customers appreciate the follow-up — it often prompts questions they had forgotten to ask and demonstrates a professional, attentive approach."}, {"question": "Can automations connect to tools I already use?", "answer": "Yes. We integrate with common tools plumbers use including Google Calendar, QuickBooks, Xero, ServiceM8, and Tradify. If you track jobs in a spreadsheet or notebook, we can build automations around that too. The goal is to enhance your existing workflow without forcing you to learn new software."}]'
)
ON CONFLICT (industry_slug, service_slug) DO UPDATE SET
  intro_paragraph = EXCLUDED.intro_paragraph,
  why_needed = EXCLUDED.why_needed,
  approach_difference = EXCLUDED.approach_difference,
