  faqs = EXCLUDED.faqs;

-- 5. Plumbers × Branding
INSERT INTO public.industry_content (industry_slug, service_slug, intro_paragraph, why_needed, approach_difference, pain_points, solutions, faqs)
VALUES (
  'plumbers',
  'branding',
  'Plumbing is one of the few trades where customers routinely let a stranger into their home to access their most private spaces — bathrooms, kitchens, bedrooms with en-suites. Trust is not just important; it is the prerequisite for every job. Your brand is the first signal of trustworthiness, and it is judged in multiple contexts: the van parked on the driveway, the uniform worn at the front door, the quote document emailed after a site visit, and the Google listing seen during the initial search. Most plumbing businesses operate with a clip-art logo featuring a spanner or dripping tap, inconsistent colours across their van and website, and quotes sent as plain text emails. This generic, unprofessional presentation makes it impossible to differentiate from dozens of other plumbers in the area and undermines the trust needed for customers to hand over their house keys for a boiler installation lasting several days. We create complete brand identities for plumbing businesses that communicate reliability, technical competence, and professionalism across every customer touchpoint from the first Google search to the final invoice.',
  'Customers choose plumbers based on perceived trustworthiness more than any other factor. A cohesive, professional brand — consistent across your van, website, workwear, and documentation — immediately distinguishes your business from the majority of plumbers running mismatched visuals. Strong branding also supports premium pricing for high-value work like boiler installations and bathroom fitting, where customers associate visual professionalism with quality workmanship and reliability.',
  'We design plumbing brands that project technical competence and reliability — clean, confident design systems using strong, trust-associated colour palettes. No clip-art spanners or cartoon water drops. Every brand system is tested across van livery, workwear embroidery, Gas Safe branded documentation, and digital assets before finalisation.',
  '[{"title": "Generic branding indistinguishable from every other plumber", "description": "Clip-art spanners, cartoon water drops, and blue-and-white colour schemes dominate plumbing branding. When every plumber in the area looks identical, customers cannot differentiate based on brand impression and default to choosing on price alone — undermining the premium positioning that quality workmanship deserves."}, {"title": "Van livery failing to build trust on residential driveways", "description": "A plumber''s van parked on a customer''s driveway is visible to every neighbour. Cheap vinyl lettering, faded wraps, and cluttered designs fail to project the professionalism that generates referral enquiries from neighbours watching through their windows. The van is your most visible marketing asset, and most plumbing vans waste it."}, {"title": "Quote documents that undermine the value of technical expertise", "description": "Plumbers quoting thousands of pounds for boiler installations or bathroom renovations often send plain text emails or handwritten estimates. Without a professionally designed quote template reflecting your Gas Safe accreditation, manufacturer certifications, and the technical scope of the work, customers struggle to see the value behind the price."}]',
  '[{"title": "Trust-first brand identity system", "description": "We design brand identities built around trust signals: strong, authoritative colour palettes, clean modern typography, and design elements that communicate technical competence and reliability. The brand system works cohesively across digital and physical formats, creating a consistent professional impression at every customer interaction."}, {"title": "Professional van livery designed for residential trust", "description": "Van designs that project competence and reliability on residential driveways: clean layouts, legible contact details, Gas Safe registration displayed prominently, and a design that stands apart from the generic plumbing vans parked on every street. The livery builds trust with the customer and generates enquiries from neighbours."}, {"title": "Branded technical documentation and quote templates", "description": "Professional quote and estimate templates featuring your brand identity, Gas Safe registration, manufacturer accreditations, detailed scope of work breakdowns, and warranty information. These documents elevate the sales process for high-value work like boiler installations and bathroom fitting, justifying premium pricing through professional presentation."}]',
  '[{"question": "What should a plumbing brand communicate?", "answer": "Reliability, technical competence, and trustworthiness. The most effective plumbing brands use strong, confident colour palettes — deep blues, charcoal greys, or teals — combined with clean modern typography. The brand should feel professional and established rather than generic or gimmicky, reflecting the serious nature of gas and water work."}, {"question": "Do you design van livery for plumbers?", "answer": "Yes. Van livery is a central component of our plumbing branding packages. We create wrap or vinyl designs optimised for your vehicle type, prominently displaying your Gas Safe registration, phone number, and services. The design is clean, professional, and distinct from the generic plumbing van aesthetic."}, {"question": "Can professional branding really help me charge more?", "answer": "Yes. For considered purchases like boiler installations and bathroom renovations, customers use visual cues to assess quality before speaking to you. Consistent branding across your van, website, workwear, and quotes positions you as an established professional, making customers more comfortable with higher pricing than they would accept from an unbranded sole trader."}, {"question": "How long does a plumbing brand identity take to complete?", "answer": "A complete brand identity including logo, colour system, typography, van livery design, workwear specifications, documentation templates, and brand guidelines takes three to four weeks from initial brief to final delivery. We present concepts after week one, refine based on your feedback, and deliver all production-ready files and specifications."}]'
)
ON CONFLICT (industry_slug, service_slug) DO UPDATE SET
