-- 6. Plumbers × Social Media Setup
INSERT INTO public.industry_content (industry_slug, service_slug, intro_paragraph, why_needed, approach_difference, pain_points, solutions, faqs)
VALUES (
  'plumbers',
  'social-media-setup',
  'Plumbing might not seem like natural social media content, but the reality is that behind-the-scenes plumbing work generates genuine fascination and engagement. Timelapse boiler installations, before-and-after bathroom transformations, drain camera footage revealing what caused a blockage, and seasonal heating tips all perform well on platforms like Instagram and Facebook. The problem is that most plumbers either have no social presence or post occasionally with no consistency, branding, or strategy. Setting up social media properly for a plumbing business means creating branded profiles that communicate Gas Safe credentials, establishing content categories that showcase different aspects of your work, and building a documentation system that makes capturing content on-site genuinely effortless alongside a physically demanding work schedule. A well-maintained social presence demonstrates active trading, builds trust through visible completed work, and generates referrals when satisfied customers share your posts with friends facing similar plumbing issues. We set up social media for plumbers with branded templates, content calendars, and capture systems designed for tradespeople who work with pipes, not pixels.',
  'Homeowners and landlords increasingly check social media before hiring a plumber, looking for evidence of recent work, professional presentation, and customer satisfaction. A plumber with no social presence raises questions about trading status and reliability. Regular posts showing completed boiler installations, bathroom projects, and satisfied customers build the social proof that converts cautious prospects into booked jobs, particularly for high-value planned work.',
  'We set up plumbing social accounts with project documentation templates for boiler installations and bathroom renovations, quick-capture formats for emergency callout stories, and seasonal content calendars aligned to heating demand cycles. Photo guidelines ensure your team can document work on-site in thirty seconds between tasks.',
  '[{"title": "No social media presence despite completing impressive work daily", "description": "Plumbers complete boiler installations, bathroom renovations, and complex pipework modifications every week, but none of this work reaches social media. These projects — particularly bathroom before-and-after transformations — generate strong engagement and build trust with prospective customers who never see evidence of your capabilities."}, {"title": "Sporadic posting creating an impression of inactivity", "description": "A Facebook page with the last post from four months ago looks worse than having no social presence at all. Potential customers assume the business is struggling or no longer trading. Without a sustainable posting system, social media becomes an inconsistent liability rather than a consistent marketing asset."}, {"title": "No time or system for capturing content while working", "description": "Plumbers work physically demanding schedules in cramped, dark spaces with dirty hands. Without an extremely simple, fast system for documenting work on-site, social media content never gets captured and the marketing opportunity of every completed job is permanently lost."}]',
  '[{"title": "Professionally branded plumbing social profiles", "description": "We set up Instagram, Facebook, and Google Business profiles with consistent branding, Gas Safe credentials displayed prominently, and bios highlighting your key services and coverage area. Organised highlights showcase bathroom projects, boiler installations, and customer testimonials in easily browsable categories."}, {"title": "Thirty-second on-site capture system", "description": "A practical documentation system designed for the realities of plumbing work: quick photo angles for before-and-after bathroom shots, boiler installation progress documentation, and a shared folder that makes uploading from a dirty phone on-site effortless. The system generates a steady content stream without disrupting your work schedule."}, {"title": "Seasonal content calendar aligned to heating demand", "description": "A twelve-month content plan timed to plumbing demand cycles: boiler service reminders before autumn, heating efficiency tips in winter, bathroom renovation inspiration in spring, and outdoor tap and drainage content in summer. Each season''s content is prepared with branded templates so posting takes minutes."}]',
  '[{"question": "Which social media platforms work best for plumbers?", "answer": "Facebook is the strongest platform for plumbers due to its community group reach and the demographic of homeowners making plumbing decisions. Instagram works well for bathroom renovation showcases and boiler installation timelapses. We set up both platforms with consistent branding and content strategies tailored to each."}, {"question": "What kind of plumbing content performs well on social media?", "answer": "Bathroom before-and-after transformations consistently generate the highest engagement. Boiler installation timelapses, drain camera footage, and heating system explanations also perform well. Seasonal tips like preparing pipes for winter or boiler servicing reminders generate shares and position you as a helpful expert."}, {"question": "How often should a plumber post on social media?", "answer": "Three posts per week is effective: one project showcase such as a bathroom reveal or boiler installation, one educational or seasonal tip, and one behind-the-scenes or customer testimonial post. Our template system makes creating each post a five-minute task rather than a creative exercise."}, {"question": "Can I manage social media myself after the initial setup?", "answer": "Yes. Our setup includes branded templates, a content calendar, and a quick-capture guide specifically designed for tradespeople. Most plumbers find they can maintain their social presence in under twenty minutes per week once the system and templates are in place. We train you on the process during handover."}]'
)
ON CONFLICT (industry_slug, service_slug) DO UPDATE SET
  intro_paragraph = EXCLUDED.intro_paragraph,
  why_needed = EXCLUDED.why_needed,
