  faqs = EXCLUDED.faqs;

-- 7. Plumbers × Digital Marketing
INSERT INTO public.industry_content (industry_slug, service_slug, intro_paragraph, why_needed, approach_difference, pain_points, solutions, faqs)
VALUES (
  'plumbers',
  'digital-marketing',
  'Digital marketing for plumbing businesses must account for two fundamentally different customer journeys: the emergency caller who needs a plumber in the next hour, and the homeowner planning a boiler replacement or bathroom renovation over the coming weeks. Most plumbing digital marketing either focuses entirely on emergency Google Ads — burning through budget on competitive clicks — or takes a generic "post on Facebook and hope" approach that generates minimal return. An effective plumbing digital marketing strategy coordinates multiple channels with distinct objectives: Google Ads for emergency callout visibility during off-peak organic ranking periods, remarketing campaigns targeting boiler quote page visitors who did not convert, email marketing to existing customers for annual service reminders, and social media campaigns timed to seasonal heating demand. Each channel serves a specific commercial purpose with measurable outcomes. We build integrated digital marketing strategies for plumbers that capture emergency demand, nurture planned-project researchers through to booking, and reactivate past customers for recurring service revenue.',
  'Relying on a single marketing channel — whether that is word of mouth, Checkatrade, or Google Ads alone — leaves your plumbing business vulnerable to fluctuations you cannot control. Checkatrade raises fees, Google Ads costs increase during winter demand spikes, and word of mouth slows during quiet periods. A diversified digital marketing strategy across search, social, email, and remarketing creates multiple revenue streams, smoothing seasonal demand and reducing dependency on any single source.',
  'We build plumbing marketing strategies around revenue priorities: emergency callout campaigns on Google targeting after-hours searches, boiler installation remarketing for quote page visitors, email campaigns to existing customers timed to annual service cycles, and seasonal social media campaigns ahead of winter heating demand. Every channel is measured against cost per enquiry.',
  '[{"title": "Google Ads spending generating calls but poor return on investment", "description": "Many plumbers run Google Ads targeting broad terms like plumber near me and pay premium rates per click during competitive periods. Without proper call tracking, negative keyword management, and landing page optimisation, a significant portion of ad spend generates irrelevant calls — tenants calling about landlord responsibilities, DIY advice seekers, or locations outside your service area."}, {"title": "No marketing strategy for high-value planned work", "description": "Boiler installations and bathroom renovations are the most profitable plumbing services, yet most marketing efforts focus on emergency callout visibility. Without dedicated campaigns targeting homeowners researching these considered purchases — through content, remarketing, and email nurture — you compete solely on price for the highest-value work."}, {"title": "Seasonal demand swings with no proactive marketing", "description": "Plumbing demand peaks in winter with heating failures and frozen pipes, then drops through summer. Without proactive marketing — promoting boiler servicing before autumn, bathroom renovations during quieter months, and outdoor plumbing work in summer — your revenue follows the same seasonal rollercoaster without any smoothing."}]',
  '[{"title": "Emergency Google Ads with call tracking and optimisation", "description": "Targeted Google Ads campaigns for emergency plumbing searches with proper call tracking, negative keyword exclusions for irrelevant searches, and landing pages designed for instant conversion. We optimise based on which keywords generate genuine paying callouts rather than just phone calls, improving your cost per actual job."}, {"title": "Boiler installation remarketing campaigns", "description": "Visitors who view your boiler installation or bathroom fitting pages but do not convert see targeted remarketing ads across Google and Facebook over the following thirty days. These campaigns keep your business visible during the consideration period and recapture prospects who were comparing multiple plumbers before making a decision."}, {"title": "Seasonal email and social campaigns timed to plumbing demand", "description": "Pre-winter boiler service campaigns to existing customers, spring bathroom renovation promotions, and autumn heating system health-check offers are coordinated across email and social media. These proactive campaigns smooth seasonal demand, generate recurring service revenue, and reactivate past customers before they search for a competitor."}]',
  '[{"question": "How much should a plumber spend on digital marketing?", "answer": "Most plumbing businesses see strong returns from a monthly investment of five hundred to fifteen hundred pounds across Google Ads, social media, and email marketing. We recommend starting with Google Ads for emergency and boiler installation terms, then expanding to remarketing and email as your enquiry pipeline develops. Every pound is tracked against actual jobs generated."}, {"question": "Should I use Google Ads or SEO for emergency plumbing searches?", "answer": "Both, with different timeframes. Google Ads provide immediate visibility for emergency searches while SEO builds long-term organic positioning. We typically run both in parallel, with Ads covering competitive terms while SEO gains traction. As organic rankings strengthen, we reduce ad spend on terms where you already rank well."}, {"question": "Can digital marketing help during the quieter summer months?", "answer": "Yes. Summer campaigns promoting bathroom renovations, outdoor tap installations, and boiler replacement planning ahead of winter capture work during your quietest period. Email campaigns to existing customers about annual boiler servicing and power flush offers generate revenue from your established base during seasonal lulls."}, {"question": "How do you measure whether plumbing marketing is working?", "answer": "We track cost per enquiry and cost per booked job for every channel. Call tracking identifies which campaigns generate phone calls, form tracking attributes online enquiries to specific ads or content, and revenue tracking calculates your return on investment per channel. Monthly reports show exactly what each marketing pound produces."}]'
)
ON CONFLICT (industry_slug, service_slug) DO UPDATE SET
  intro_paragraph = EXCLUDED.intro_paragraph,
  why_needed = EXCLUDED.why_needed,
  approach_difference = EXCLUDED.approach_difference,
  pain_points = EXCLUDED.pain_points,
  solutions = EXCLUDED.solutions,
  faqs = EXCLUDED.faqs;

-- 8. Plumbers × Workwear & Print
INSERT INTO public.industry_content (industry_slug, service_slug, intro_paragraph, why_needed, approach_difference, pain_points, solutions, faqs)
VALUES (
  'plumbers',
  'workwear-print',
  'A plumber''s workwear is seen by every customer who opens their front door, every neighbour watching from across the street, and every merchant at the trade counter. It is your most personal brand touchpoint — the moment a homeowner decides whether they feel comfortable letting you into their home. Branded workwear for plumbers serves both a trust function and a marketing function: a clean, professionally embroidered polo shirt or softshell jacket immediately signals that this is an established business rather than an unknown individual, while the visible branding reinforces your name and phone number with everyone who sees you throughout the working day. Beyond workwear, printed materials complete the professional impression: branded business cards left after a quote visit, magnetic vehicle signs for personal vehicles used on weekends, invoice pads with Gas Safe registration details, and customer care cards explaining what to do if they have issues. We supply branded workwear and printed materials for plumbing businesses that build trust at the doorstep and keep your details in customers'' hands long after the job is finished.',
  'Plumbers enter customers'' most private spaces — bathrooms, bedrooms, kitchens — and homeowners make instant judgements about trustworthiness based on appearance. Branded workwear immediately elevates perception from "stranger at the door" to "professional from an established business." Printed materials — business cards, care cards, invoice books — extend that professional impression beyond the visit, keeping your details accessible when the customer recommends you or needs further work.',
  'We supply plumbing workwear designed for the physical demands of the trade: embroidered polo shirts for customer-facing work, branded softshell jackets for outdoor and loft work, and printed hi-vis vests for commercial sites. Printed materials include Gas Safe branded business cards, magnetic vehicle signs, customer care cards, and professional invoice pads.',
  '[{"title": "Arriving at customer properties in unbranded clothing", "description": "A plumber arriving in a plain t-shirt and jeans is immediately less trusted than one wearing a branded, clean uniform. Homeowners opening their front door make a split-second assessment of professionalism, and unbranded clothing offers no reassurance that this person represents an established, accountable business."}, {"title": "No business cards or leave-behind materials after quote visits", "description": "After visiting a property to quote a boiler installation or bathroom renovation, leaving nothing behind means the customer has no physical reminder of your business. When they compare quotes days later, the plumber who left a professional business card with Gas Safe registration details has a tangible advantage."}, {"title": "Workwear that does not withstand the physical demands of plumbing", "description": "Cheap promotional clothing that rips, fades, or stains after a few days of plumbing work wastes money and damages your brand appearance. Plumbers need workwear that withstands crawling through loft spaces, kneeling on hard floors, and exposure to water and chemicals while maintaining a professional appearance."}]',
  '[{"title": "Trade-grade branded workwear for plumbing professionals", "description": "Embroidered polo shirts, softshell jackets, and fleeces in your brand colours using trade-grade fabrics that withstand the physical demands of plumbing work. Reinforced stitching, stain-resistant treatments, and durable embroidery ensure your branding looks professional after months of daily wear in challenging conditions."}, {"title": "Gas Safe branded business cards and leave-behind materials", "description": "Professional business cards displaying your Gas Safe registration number, services offered, emergency contact details, and a QR code linking to your website. Customer care cards explaining post-installation guidance and warranty details provide genuine value while keeping your contact information in the customer''s home."}, {"title": "Magnetic vehicle signs and printed documentation", "description": "Magnetic vehicle signs for personal vehicles used on evening and weekend callouts, branded invoice pads with Gas Safe details and payment terms, and vehicle window stickers displaying your registration and contact information. These materials ensure consistent branding whether you are in the branded van or a personal vehicle."}]',
  '[{"question": "What workwear do you recommend for plumbers?", "answer": "We recommend embroidered polo shirts for customer-facing visits, branded softshell jackets for outdoor and loft work, and printed hi-vis vests for commercial sites. All garments use trade-grade fabrics with reinforced stitching and stain-resistant treatments designed to maintain a professional appearance through the physical demands of daily plumbing work."}, {"question": "Can you include my Gas Safe registration on business cards?", "answer": "Yes. Gas Safe registration displayed on business cards is a powerful trust signal. We include your registration number, the Gas Safe logo subject to their branding guidelines, your services, emergency contact number, and a QR code linking to your website or Gas Safe verification page."}, {"question": "How long does branded plumbing workwear last?", "answer": "Our trade-grade workwear is selected for durability in demanding conditions. Polo shirts typically last six to twelve months of daily wear before replacement, while softshell jackets and fleeces last considerably longer. Embroidery is more durable than printing and maintains a professional appearance through repeated washing."}, {"question": "Can I order small quantities of workwear?", "answer": "Yes. We cater to sole traders and small plumbing teams, with minimum orders typically starting at five to ten garments. Business cards, vehicle magnetics, and other printed materials have similarly accessible minimum quantities. We stock your brand specifications for easy reordering as workwear needs replacing."}]'
)
ON CONFLICT (industry_slug, service_slug) DO UPDATE SET
  intro_paragraph = EXCLUDED.intro_paragraph,
  why_needed = EXCLUDED.why_needed,
  approach_difference = EXCLUDED.approach_difference,
  pain_points = EXCLUDED.pain_points,
  solutions = EXCLUDED.solutions,
  faqs = EXCLUDED.faqs;

-- 9. Plumbers × AI Chatbots
INSERT INTO public.industry_content (industry_slug, service_slug, intro_paragraph, why_needed, approach_difference, pain_points, solutions, faqs)
VALUES (
  'plumbers',
  'ai-chatbots',
  'Plumbing enquiries arrive at the worst possible times — a boiler failure at ten at night, a leak discovered on a Saturday morning, a burst pipe while you are already on a job with your hands full. Every missed call is a lost customer, because emergency plumbing callers do not leave voicemails; they call the next number on Google. An AI chatbot built for a plumbing business does not just answer frequently asked questions — it performs emergency triage, distinguishing a genuine burst pipe requiring immediate callout from a dripping tap that can be scheduled for next week. It collects critical information: the nature of the problem, whether water is actively flowing, whether the stopcock has been located and turned off, and the customer''s address and contact details. For non-emergency enquiries, the chatbot gathers boiler model details, describes symptoms, estimates property size for heating work, and books consultation slots directly into your calendar. The result is that emergency callers receive instant guidance and you receive a prioritised alert, while planned-work enquiries are qualified and scheduled without you lifting a finger. We build AI chatbots for plumbers that triage emergencies intelligently, capture every enquiry around the clock, and ensure no job is lost to a missed call.',
  'Plumbing businesses lose their most valuable leads — emergency callouts paying premium rates — to missed calls during working hours and after-hours downtime. An AI chatbot ensures every visitor to your website receives an instant response at any hour. Emergency situations are triaged with immediate safety guidance while alerting you to the callout. Non-urgent enquiries are fully qualified with problem details, property information, and preferred scheduling — ready for you to review when you finish the current job.',
  'We build plumbing chatbots with emergency triage logic: identifying active leaks, gas smells, and flooding situations that need immediate response versus routine repairs and planned installations. The chatbot walks emergency callers through safety steps like locating the stopcock, then sends you a priority alert. Non-emergency interactions collect boiler details, symptom descriptions, and schedule consultations automatically.',
  '[{"title": "Emergency calls missed while working on other jobs", "description": "A plumber cannot answer the phone while brazing a pipe joint or working in a confined loft space. Every unanswered call during a genuine emergency — a burst pipe, a gas smell, a boiler failure in freezing weather — sends a premium-paying customer directly to a competitor. These are the highest-value leads in plumbing, and they are the most likely to be missed."}, {"title": "After-hours enquiries lost entirely", "description": "Boiler failures and leaks do not respect working hours. Website visitors at eleven at night who cannot reach you will not fill in a contact form and wait — they need help now. Without an AI chatbot providing instant interaction, triaging their emergency, and offering safety guidance, these after-hours visitors call the first competitor with a visible phone number."}, {"title": "Time wasted qualifying non-emergency enquiries by phone", "description": "Routine calls about boiler servicing, radiator additions, and bathroom quotes consume valuable time when you are between jobs. Each call requires asking the same qualifying questions: property type, boiler model, number of radiators, symptoms. An AI chatbot collects all of this information before you are involved, letting you review fully qualified enquiries at your convenience."}]',
  '[{"title": "Emergency triage with safety guidance and priority alerting", "description": "The chatbot identifies emergency situations through targeted questions: Is water actively flowing? Can you smell gas? Is the property losing heating in freezing conditions? Emergency callers receive immediate safety instructions — locate and turn off the stopcock, open windows for gas smells, use the emergency gas number for suspected leaks — while you receive a priority SMS alert with the customer''s details and situation summary."}, {"title": "Instant boiler and heating enquiry qualification", "description": "For non-emergency heating enquiries, the chatbot collects boiler make, model, and age; describes symptoms; asks about property size and radiator count; and captures the customer''s budget expectations and timeline. You receive a fully qualified lead with all the technical details needed to prepare an accurate estimate before contacting the customer."}, {"title": "Automated callout and consultation booking", "description": "The chatbot accesses your calendar availability and allows customers to book emergency callout windows or planned consultation slots directly. Emergency bookings trigger immediate notifications. Planned consultations are confirmed automatically with address details, access instructions, and a reminder sent the day before."}]',
  '[{"question": "Can an AI chatbot really handle plumbing emergency triage?", "answer": "Yes. We programme the chatbot with a structured triage flow that identifies emergency indicators: active water leaks, gas smells, complete heating failure in cold weather, and flooding. The chatbot provides immediate safety guidance appropriate to each situation while simultaneously alerting you with the customer''s details and a priority classification."}, {"question": "What happens when the chatbot identifies a genuine emergency?", "answer": "You receive an immediate SMS and email alert with the customer''s name, address, phone number, and a summary of the emergency — for example, ''active leak from upstairs bathroom, stopcock located and turned off, ceiling showing water damage.'' This gives you everything needed to call back or dispatch within minutes."}, {"question": "Can the chatbot book callouts directly into my calendar?", "answer": "Yes. The chatbot integrates with Google Calendar, Calendly, or your preferred scheduling system. Customers can book available time slots for consultations and non-emergency visits. Emergency requests bypass normal scheduling and trigger immediate alerts, but the customer is informed of your typical response time."}, {"question": "Will customers be frustrated talking to a chatbot instead of a real plumber?", "answer": "The chatbot is designed to be genuinely helpful — providing safety guidance during emergencies, collecting information efficiently, and offering real appointment booking. Most customers prefer instant interaction over leaving a voicemail and waiting for a callback. The chatbot handles the initial interaction, and you follow up personally for complex discussions."}]'
)
ON CONFLICT (industry_slug, service_slug) DO UPDATE SET
  intro_paragraph = EXCLUDED.intro_paragraph,
  why_needed = EXCLUDED.why_needed,
  approach_difference = EXCLUDED.approach_difference,
  pain_points = EXCLUDED.pain_points,
  solutions = EXCLUDED.solutions,
  faqs = EXCLUDED.faqs;

-- 10. Plumbers × AI Content
INSERT INTO public.industry_content (industry_slug, service_slug, intro_paragraph, why_needed, approach_difference, pain_points, solutions, faqs)
VALUES (
  'plumbers',
  'ai-content',
  'Content marketing for plumbers faces a unique challenge: the topics that drive the most valuable search traffic — boiler installation guides, central heating troubleshooting, emergency plumbing advice — require genuine technical accuracy. Generic content written by someone who has never bled a radiator or replaced a flue terminal reads as obviously inauthentic to both Google and customers. AI content creation for plumbers combines the efficiency of artificial intelligence with your real-world technical knowledge to produce content that is both search-optimised and technically credible. We use AI tools trained on plumbing industry knowledge to draft content that covers the technical details homeowners search for: boiler error codes and their meanings, the difference between combi and system boilers, how to identify a leaking pressure relief valve, and when to call a Gas Safe engineer versus attempting a fix themselves. Your expertise shapes and validates every piece, ensuring accuracy and authenticity. The result is a consistent stream of technically sound content that drives organic traffic, demonstrates your expertise, and generates enquiries from homeowners who trust your knowledge before they ever meet you.',
  'Plumbing businesses that publish regular, technically accurate content dominate local search results because Google rewards demonstrated expertise. But producing quality content requires time that working plumbers do not have. AI content tools bridge this gap, generating draft articles and service page copy that you refine with your practical knowledge. The result is a consistent publishing schedule that builds search authority without consuming your evenings writing blog posts.',
  'We use AI to draft technically focused plumbing content — boiler comparison guides, fault diagnosis articles, heating system explainers — then refine each piece with industry-specific accuracy checks. Your real-world experience validates every claim. Content is optimised for the specific search terms homeowners use when researching plumbing services and problems.',
  '[{"title": "No time to write content despite having valuable expertise", "description": "Plumbers possess exactly the technical knowledge that homeowners search for — boiler fault diagnosis, heating system advice, emergency plumbing guidance — but spend their entire working day on-site with no time to write articles. This expertise remains locked in your head while competitors who publish content consistently outrank you."}, {"title": "Generic content that lacks technical credibility", "description": "Content written by marketing agencies without plumbing knowledge is often technically inaccurate or superficial. Articles that confuse combi and system boilers, misidentify common fault codes, or give dangerous advice about gas appliances damage your credibility and can create legal liability."}, {"title": "Inconsistent publishing undermining SEO momentum", "description": "Plumbing businesses that publish a few articles and then stop see initial ranking improvements that plateau and decline. Search engines reward consistent content publication, and competitors who maintain a regular schedule steadily overtake businesses that publish sporadically."}]',
  '[{"title": "AI-drafted technical content validated by your expertise", "description": "We use AI tools to draft comprehensive plumbing content — boiler buying guides, fault diagnosis articles, heating efficiency tips, emergency response guides — then work with you to validate technical accuracy. A fifteen-minute review call per article ensures every piece reflects real-world plumbing knowledge while AI handles the time-consuming writing."}, {"title": "Boiler and heating system content targeting high-value searches", "description": "Targeted content covering boiler error codes for specific manufacturers, combi versus system boiler comparisons, and central heating troubleshooting guides. These articles attract homeowners actively researching heating decisions worth thousands of pounds, positioning your business as the knowledgeable expert they contact for installation or repair."}, {"title": "Consistent monthly publishing schedule building search authority", "description": "A managed content calendar delivers four to eight optimised articles per month covering seasonal plumbing topics, technical guides, and local service content. Consistent publication builds the topical authority that Google rewards with higher rankings across all your service pages, not just the individual articles."}]',
  '[{"question": "How does AI content creation work for a plumbing business?", "answer": "We use AI tools to draft content based on the search terms homeowners use when researching plumbing services. Each draft covers the technical details accurately but is then reviewed with you — typically in a fifteen-minute call — to add your real-world insights, correct any technical nuances, and ensure the content reflects your genuine expertise."}, {"question": "Will AI-generated content sound authentic to plumbing customers?", "answer": "Yes, because every piece is validated by your real-world experience. We add your practical insights, real examples from your work, and the technical details that only a working plumber would know. The AI handles structure and SEO optimisation; your expertise provides the authenticity that resonates with readers and search engines."}, {"question": "What plumbing topics generate the most valuable search traffic?", "answer": "Boiler installation guides, boiler error code explainers, heating system comparisons, and emergency plumbing advice generate the highest-value traffic. Homeowners reading boiler replacement guides are researching purchases worth several thousand pounds. Those searching for error codes often need urgent professional help. Both represent high-value leads."}, {"question": "How many articles per month should a plumber publish?", "answer": "Four to eight articles per month delivers strong SEO results for plumbing businesses. We balance evergreen technical content like boiler buying guides with seasonal topics like preparing pipes for winter and timely pieces responding to regulatory changes. This mix builds sustained search visibility while capturing seasonal demand."}]'
)
ON CONFLICT (industry_slug, service_slug) DO UPDATE SET
  intro_paragraph = EXCLUDED.intro_paragraph,
  why_needed = EXCLUDED.why_needed,
  approach_difference = EXCLUDED.approach_difference,
  pain_points = EXCLUDED.pain_points,
  solutions = EXCLUDED.solutions,
  faqs = EXCLUDED.faqs;

-- 11. Plumbers × AI Automation
INSERT INTO public.industry_content (industry_slug, service_slug, intro_paragraph, why_needed, approach_difference, pain_points, solutions, faqs)
VALUES (
  'plumbers',
  'ai-automation',
  'AI automation for plumbing businesses goes beyond simple task scheduling into intelligent decision-making that adapts to the realities of trade work. Traditional automation sends a follow-up email on a timer; AI automation reads an incoming enquiry, determines whether it describes an emergency or a planned project, extracts the relevant technical details — boiler model, fault symptoms, property type — and routes it appropriately. An emergency description triggers an instant priority alert to your phone with a triage summary. A boiler replacement enquiry is automatically enriched with manufacturer warranty status checks and typical replacement costs for that model before you even see it. Quote follow-ups are timed intelligently based on the type and value of the work quoted — a twenty-thousand-pound bathroom renovation gets a different follow-up cadence than a three-hundred-pound radiator replacement. AI automation transforms a plumbing business from reactive to predictive, anticipating customer needs, prioritising your time toward the highest-value opportunities, and handling routine operational decisions that currently rely on you remembering to act. We build AI-powered automation systems for plumbers that think about your business while you focus on the work.',
  'Plumbing businesses generate a constant stream of decisions: which enquiry to respond to first, when to follow up a quote, which boiler service reminder to send, whether an incoming message describes an emergency. AI automation makes these decisions intelligently and instantly, ensuring emergency callers get immediate attention, high-value quotes get timely follow-up, and routine operations run without your involvement.',
  'We build AI automations that understand plumbing context: classifying enquiries by urgency and value, extracting technical details from customer messages, routing emergencies for instant response, enriching boiler enquiries with model-specific data, and intelligently timing follow-ups based on job type. Every automation learns from your preferences and improves over time.',
  '[{"title": "Emergency enquiries buried among routine messages", "description": "A message describing an active ceiling leak arrives alongside three boiler service requests and a bathroom quote enquiry. Without intelligent classification, the emergency sits in the same queue as everything else, and the customer calls a competitor while you work through messages in order. AI automation identifies emergencies instantly and escalates them."}, {"title": "One-size-fits-all follow-up timing losing high-value work", "description": "Following up a ten-thousand-pound boiler and heating system quote with the same timing as a two-hundred-pound tap replacement is commercially naive. High-value work requires more considered, strategically timed follow-up with additional supporting materials, while small repairs benefit from quick, simple reminders."}, {"title": "Manual processing of every enquiry consuming valuable time", "description": "Reading every incoming message, extracting the relevant details, classifying the urgency, and deciding on next steps consumes time that a plumber does not have during a busy working day. By the time you process the morning''s messages in the evening, the most urgent ones are hours old and the customers have found another plumber."}]',
  '[{"title": "Intelligent enquiry classification and emergency routing", "description": "AI reads every incoming enquiry — from website forms, emails, and chatbot conversations — and classifies it by urgency and commercial value. Descriptions mentioning active leaks, gas smells, or heating failure trigger instant priority alerts to your phone. Planned work enquiries are categorised, enriched with relevant details, and queued for your review."}, {"title": "Quote follow-up sequences tailored to job value and type", "description": "AI determines the appropriate follow-up cadence based on the type and value of quoted work. Boiler installation quotes receive a structured sequence with manufacturer information, finance options, and efficiency comparisons. Bathroom renovation quotes include design inspiration and project timeline reassurance. Small repair quotes get quick, simple reminders."}, {"title": "Predictive service reminders and customer lifecycle management", "description": "AI tracks every customer interaction and predicts when they will need your services next — annual boiler servicing, gas safety certificate renewals, and estimated timelines for replacement based on boiler age and service history. Proactive outreach reaches customers before they start searching for another plumber, securing repeat business automatically."}]',
  '[{"question": "How does AI automation differ from regular automation for plumbers?", "answer": "Regular automation follows fixed rules — send a follow-up after forty-eight hours regardless of context. AI automation understands context: it reads enquiry details, classifies urgency, extracts technical information, and adapts its responses and timing accordingly. An emergency gets instant escalation; a boiler quote gets a value-appropriate follow-up sequence with relevant supporting content."}, {"question": "Can AI really tell the difference between a plumbing emergency and a routine enquiry?", "answer": "Yes. The AI is trained to identify emergency indicators in customer messages: mentions of active leaks, water damage, gas smells, complete heating failure, and flooding. It distinguishes between a dripping tap that can wait and a burst pipe that needs immediate attention, routing each appropriately with the correct urgency level."}, {"question": "Will AI automation replace the need for me to handle customer enquiries personally?", "answer": "No. AI handles the initial classification, information extraction, and routing. Emergency alerts still come to you for personal response. High-value quotes are prepared with enriched information for you to review and personalise. The AI removes the administrative burden of processing enquiries, allowing you to focus your personal attention where it matters most."}, {"question": "How does AI improve over time for my plumbing business?", "answer": "The system learns from your feedback and actions. When you override a classification or adjust a follow-up timing, the AI incorporates this preference into future decisions. Over months, it develops an increasingly accurate understanding of your business priorities, customer base, and preferred working patterns."}]'
)
ON CONFLICT (industry_slug, service_slug) DO UPDATE SET
  intro_paragraph = EXCLUDED.intro_paragraph,
  why_needed = EXCLUDED.why_needed,
  approach_difference = EXCLUDED.approach_difference,
  pain_points = EXCLUDED.pain_points,
  solutions = EXCLUDED.solutions,
  faqs = EXCLUDED.faqs;
